INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Lúa', 'Cây lương thực chủ lực của Việt Nam, trồng nhiều ở ĐBSCL và ĐB sông Hồng.', 'Làm đất kỹ, bón lót lân; giữ mực nước 3-5cm giai đoạn đẻ nhánh; phòng đạo ôn, rầy nâu; bón cân đối NPK theo 3 giảm 3 tăng.', 'Phơi khô đến độ ẩm 13-14%, bảo quản nơi khô thoáng, tránh mọt.', 'Đồng bằng sông Cửu Long, Đồng bằng sông Hồng', 'Vụ Đông Xuân (2-4), Hè Thu (7-9)', 'VietGAP');
INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Cà phê Robusta', 'Cà phê vối, chịu nóng tốt, chiếm phần lớn sản lượng Tây Nguyên.', 'Trồng nơi đủ nắng, tưới đủ mùa khô; tỉa cành tạo tán; bón phân sau thu hoạch; phòng rệp sáp và bệnh gỉ sắt.', 'Phơi/sấy hạt đến độ ẩm 12-13%, bảo quản trong bao kín, nơi khô ráo.', 'Đắk Lắk, Gia Lai, Đắk Nông, Lâm Đồng', 'Thu hoạch tháng 10-12', 'Tự nhiên');
INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Cà phê Arabica', 'Cà phê chè, hương vị tinh tế, thích hợp vùng cao mát.', 'Trồng độ cao trên 1000m, cần che bóng; phòng sâu đục thân và bệnh khô cành; thu hái quả chín đỏ.', 'Sơ chế ướt hoặc honey, phơi đều, bảo quản kín tránh ẩm mốc.', 'Lâm Đồng (Cầu Đất), Sơn La, Điện Biên', 'Thu hoạch tháng 11-1', 'Tự nhiên');
INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Cam sành', 'Cây có múi giàu vitamin C, vỏ dày, nhiều nước.', 'Trồng đất thoát nước tốt; bón phân hữu cơ; phòng sâu vẽ bùa, bệnh vàng lá greening; tỉa cành thông thoáng.', 'Bảo quản nơi mát 8-10°C, tránh dập, dùng trong 2-3 tuần.', 'Hòa Bình, Hà Giang, Vĩnh Long', 'Thu hoạch tháng 10-12', 'VietGAP');
INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Xoài', 'Cây ăn quả nhiệt đới, giống Cát Hòa Lộc, Cát Chu nổi tiếng.', 'Bao trái chống ruồi đục quả; bón kali giai đoạn nuôi quả; phòng thán thư, rầy bông xoài.', 'Thu hái khi quả già, ủ chín tự nhiên; bảo quản 10-13°C.', 'Tiền Giang, Đồng Tháp, An Giang', 'Thu hoạch tháng 3-6', 'VietGAP');
INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Sầu riêng', 'Cây ăn quả giá trị cao, giống Ri6, Monthong (Dona).', 'Quản lý nước nghiêm ngặt giai đoạn ra hoa; tỉa hoa tỉa trái; phòng bệnh xì mủ, nứt thân do Phytophthora.', 'Thu hoạch đúng độ chín (gõ kêu bộp); cấp đông múi nếu cần để lâu.', 'Tiền Giang, Đắk Lắk, Lâm Đồng', 'Thu hoạch tháng 5-8', 'VietGAP');
INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Thanh long', 'Cây thuộc họ xương rồng, ruột trắng/đỏ, giàu chất chống oxy hóa.', 'Làm trụ cho cây leo; chong đèn kích ra hoa trái vụ; phòng bệnh đốm nâu (nấm Neoscytalidium).', 'Bảo quản lạnh 5°C, giữ tươi 2-3 tuần.', 'Bình Thuận, Long An, Tiền Giang', 'Thu hoạch quanh năm (chính vụ 5-8)', 'VietGAP');
INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Hồ tiêu', 'Cây gia vị xuất khẩu chủ lực, hạt tiêu đen/tiêu trắng.', 'Trồng trên trụ sống/trụ chết; thoát nước tốt tránh chết nhanh chết chậm; bón hữu cơ vi sinh.', 'Phơi khô đến độ ẩm dưới 13%, bảo quản kín, tránh hút ẩm.', 'Kiên Giang (Phú Quốc), Đắk Lắk, Gia Lai, Bình Phước', 'Thu hoạch tháng 1-4', 'Chỉ dẫn địa lý');
INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Điều', 'Cây công nghiệp lấy hạt, Bình Phước là thủ phủ.', 'Trồng đất dốc thoát nước; tỉa cành tạo tán; phòng bọ xít muỗi và bệnh thán thư giai đoạn ra hoa.', 'Phơi khô hạt, bảo quản nơi thoáng tránh ẩm mốc Aflatoxin.', 'Bình Phước, Đồng Nai, Bà Rịa-Vũng Tàu', 'Thu hoạch tháng 2-4', 'Tự nhiên');
INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Vải thiều', 'Cây ăn quả đặc sản miền Bắc, nổi tiếng Lục Ngạn.', 'Khoanh cành kích ra hoa; tưới đủ giai đoạn nuôi quả; phòng sâu đục cuống và bọ xít.', 'Xử lý lạnh nhanh sau thu hoạch; bảo quản 4-5°C để giữ màu vỏ.', 'Bắc Giang (Lục Ngạn), Hải Dương (Thanh Hà)', 'Thu hoạch tháng 5-7', 'VietGAP');
INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Nhãn', 'Cây ăn quả á nhiệt đới, nhãn lồng Hưng Yên ngọt đậm.', 'Tỉa cành sau thu hoạch; xử lý ra hoa; phòng bọ xít, sâu đục quả; bón kali nuôi cùi.', 'Sấy long nhãn hoặc bảo quản lạnh; nhãn sấy giữ nơi khô kín.', 'Hưng Yên, Sơn La, ĐBSCL', 'Thu hoạch tháng 7-9', 'Truyền thống');
INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Dưa hấu', 'Cây dưa ngắn ngày, ruột đỏ ngọt mát.', 'Trồng luống cao phủ bạt; thụ phấn bổ sung; định trái; phòng bệnh héo rũ và nứt quả do tưới không đều.', 'Bảo quản nơi thoáng mát, tránh nắng trực tiếp; dùng trong 1-2 tuần.', 'Long An, Tiền Giang, Quảng Ngãi', 'Thu hoạch quanh năm', 'Tự nhiên');
INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Khoai lang', 'Cây lấy củ, giống khoai tím Nhật, mật Đà Lạt.', 'Trồng đất tơi xốp thoát nước; vun luống; phòng sùng (bọ hà) khoai lang; hạn chế đạm cuối vụ.', 'Hong khô vỏ, bảo quản nơi khô thoáng, tránh mọc mầm.', 'Vĩnh Long, Đắk Nông, Gia Lai', 'Thu hoạch sau 4-5 tháng', 'Hữu cơ');
INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Mít Thái', 'Cây ăn quả cho năng suất cao, múi giòn ngọt.', 'Tỉa trái để trái to đều; bao trái; phòng sâu đục trái và xơ đen; thoát nước tốt.', 'Tách múi cấp đông để xuất khẩu; quả nguyên bảo quản nơi mát.', 'Đồng Nai, Tiền Giang, Đắk Lắk', 'Thu hoạch quanh năm', 'VietGAP');
INSERT INTO Crop_Knowledge (crop_name, description, care_tips, storage_tips, growing_regions, harvest_months, popular_standard) VALUES ('Bơ', 'Cây ăn quả giàu chất béo tốt, giống bơ 034, bơ sáp.', 'Trồng nơi thoát nước; tạo tán; phòng bệnh thối rễ Phytophthora; thu hái khi quả đạt độ già.', 'Ủ chín tự nhiên sau thu hoạch; bảo quản mát để kéo dài.', 'Đắk Lắk, Lâm Đồng, Đắk Nông', 'Thu hoạch tháng 5-9', 'Tự nhiên');
